from typing import List
import math

class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        count = 0
        n = len(nums)
        for i in range(n):
            gcd = nums[i]
            if gcd == k:
                count += 1
            for j in range(i + 1, n):
                gcd = math.gcd(gcd, nums[j])
                if gcd == k:
                    count += 1
                elif gcd < k:
                    break
        return count
